package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.util.ArrayList;
import java.util.List;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class CSVPrinterTest {

    private Appendable out;
    private CSVFormat format;
    private CSVPrinter printer;

    @BeforeEach
    void setUp() {
        out = new StringBuilder();
        format = mock(CSVFormat.class);
        printer = new CSVPrinter(out, format);
    }

    @Test
    void testPrintRecord_withNonNullValues() throws IOException {
        StringBuilder appendable = new StringBuilder();
        CSVPrinter csvPrinter = spy(new CSVPrinter(appendable, format));

        List<String> printedValues = new ArrayList<>();

        doAnswer(invocation -> {
            Object val = invocation.getArgument(0);
            printedValues.add(String.valueOf(val));
            appendable.append(String.valueOf(val));
            return null;
        }).when(csvPrinter).print(any());

        doAnswer(invocation -> {
            appendable.append('\n');
            return null;
        }).when(csvPrinter).println();

        csvPrinter.printRecord("a", 123, true);

        assertEquals("a123true\n", appendable.toString());
        assertEquals(List.of("a", "123", "true"), printedValues);
    }

    @Test
    void testPrintRecord_withNullValues() throws IOException {
        StringBuilder appendable = new StringBuilder();
        CSVPrinter csvPrinter = spy(new CSVPrinter(appendable, format));

        List<String> printedValues = new ArrayList<>();

        doAnswer(invocation -> {
            Object val = invocation.getArgument(0);
            printedValues.add(String.valueOf(val));
            appendable.append(String.valueOf(val));
            return null;
        }).when(csvPrinter).print(any());

        doAnswer(invocation -> {
            appendable.append('\n');
            return null;
        }).when(csvPrinter).println();

        csvPrinter.printRecord("a", null, "c");

        assertEquals("anullc\n", appendable.toString());
        assertEquals(List.of("a", "null", "c"), printedValues);
    }

    @Test
    void testPrintRecord_withEmptyValues() throws IOException {
        StringBuilder appendable = new StringBuilder();
        CSVPrinter csvPrinter = spy(new CSVPrinter(appendable, format));

        doAnswer(invocation -> {
            appendable.append('\n');
            return null;
        }).when(csvPrinter).println();

        csvPrinter.printRecord();

        assertEquals("\n", appendable.toString());
    }
}
```

This version does not subclass `CSVPrinter` and uses Mockito spy to override `print` and `println` methods, satisfying the final class restriction and allowing the test to compile and run.
